using Microsoft.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");

// Load and prepare data
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var pipeline = mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(dataView);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

app.MapGet("/", () => "ChurnPredictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var result = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        churned = result.Churned,
        probability = result.Probability
    });
});

app.MapGet("/evaluate", () =>
{
    var predictions = model.Transform(dataView);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);

    return Results.Ok(new
    {
        accuracy = metrics.Accuracy,
        auc = metrics.AreaUnderRocCurve,
        f1Score = metrics.F1Score
    });
});

app.Run();

record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

